{"file_path":"/project/Issue1324Test.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class Issue1324Test {
    private val parameterListWrappingRuleAssertThat =
        assertThatRule(ParameterListWrappingRule())

    @Test
    fun `Given a nullable function type that exceeds max line length, formatting should not create conflicts`() {
        val code =
            """
            val foo1: ((s1: String, s2: String, s3: String, s4: String, s5: String, s6: String) -> Unit)? = null
            """.trimIndent()

        // This test checks that auto-correct produces consistent code
        // The expected behavior is that parameters should be wrapped properly
        val formattedCode =
            """
            val foo1: (
                (
                    s1: String,
                    s2: String,
                    s3: String,
                    s4: String,
                    s5: String,
                    s6: String
                ) -> Unit
            )? = null
            """.trimIndent()

        parameterListWrappingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 80)
            .isFormattedAs(formattedCode)

        // After formatting, running the rule again should produce no errors
        parameterListWrappingRuleAssertThat(formattedCode)
            .hasNoLintViolations()
    }
}"}

