195→            //     R> test(
196→            //     param1: T
197→            //     param2: R
198→            // )
199→            // instead of
200→            // fun <
201→            //     T,
202→            //     R> test(
203→            //         param1: T
204→            //         param2: R
205→            //     )
206→            child.treeParent.hasTypeParameterListInFront() -> -1
207→
208→            else -> 0
209→        }.let {
